 52→async function findAffectedEntities(
 53→  surreal: Surreal,
 54→  trigger: DescriptionTrigger,
 55→): Promise<AffectedEntity[]> {
 56→  const table = trigger.entity.table.name;
 57→
 58→  if (trigger.kind === "decision_confirmed" && table === "decision") {
 59→    return findEntitiesRelatedToDecision(surreal, trigger.entity);
 60→  }
 61→
 62→  if (trigger.kind === "task_completed" && table === "task") {
 63→    return findEntitiesRelatedToTask(surreal, trigger.entity);
 64→  }
 65→
 66→  if (trigger.kind === "feature_created" || trigger.kind === "feature_completed") {
 67→    return findEntitiesRelatedToFeature(surreal, trigger.entity);
 68→  }
 69→
 70→  return [];
 71→}
