 73→async function findEntitiesRelatedToDecision(
 74→  surreal: Surreal,
 75→  decisionRecord: RecordId,
 76→): Promise<AffectedEntity[]> {
 77→  // A decision belongs_to projects and features
 78→  const [rows] = await surreal
 79→    .query<[Array<{ out: RecordId }>]>(
 80→      "SELECT out FROM belongs_to WHERE `in` = $decision;",
 81→      { decision: decisionRecord },
 82→    )
 83→    .collect<[Array<{ out: RecordId }>]>();
 84→
 85→  const affected: AffectedEntity[] = [];
 86→  for (const row of rows) {
 87→    const table = row.out.table.name;
 88→    if (table === "project" || table === "feature") {
 89→      affected.push({ id: row.out, type: table });
 90→    }
 91→  }
 92→
 93→  // Also find tasks that belong to the same project/feature
 94→  if (affected.length > 0) {
 95→    const parentIds = affected.map((e) => e.id);
 96→    const [taskRows] = await surreal
 97→      .query<[Array<{ in: RecordId }>]>(
 98→        "SELECT `in` FROM belongs_to WHERE out IN $parents AND record::table(`in`) = 'task';",
 99→        { parents: parentIds },
100→      )
101→      .collect<[Array<{ in: RecordId }>]>();
102→
103→    for (const row of taskRows) {
104→      affected.push({ id: row.in, type: "task" });
105→    }
106→  }
107→
108→  return affected;
109→}
