111→async function findEntitiesRelatedToTask(
112→  surreal: Surreal,
113→  taskRecord: RecordId,
114→): Promise<AffectedEntity[]> {
115→  // A task belongs_to features and projects
116→  const [rows] = await surreal
117→    .query<[Array<{ out: RecordId }>]>(
118→      "SELECT out FROM belongs_to WHERE `in` = $task;",
119→      { task: taskRecord },
120→    )
121→    .collect<[Array<{ out: RecordId }>]>();
122→
123→  return rows
124→    .filter((row) => {
125→      const table = row.out.table.name;
126→      return table === "project" || table === "feature";
127→    })
128→    .map((row) => ({
129→      id: row.out,
130→      type: row.out.table.name as DescriptionTarget,
131→    }));
132→}
133→
134→async function findEntitiesRelatedToFeature(
135→  surreal: Surreal,
136→  featureRecord: RecordId,
137→): Promise<AffectedEntity[]> {
138→  // A feature is linked to projects via has_feature (project -> feature)
139→  const [rows] = await surreal
140→    .query<[Array<{ in: RecordId }>]>(
141→      "SELECT `in` FROM has_feature WHERE out = $feature;",
142→      { feature: featureRecord },
143→    )
144→    .collect<[Array<{ in: RecordId }>]>();
145→
146→  return rows.map((row) => ({
147→    id: row.in,
148→    type: "project" as DescriptionTarget,
149→  }));
150→}
